from collections import Counter
import string

class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = Counter(s)
        count_t = Counter(t)
        steps = 0
        for c in string.ascii_lowercase:
            steps += max(0, count_t[c] - count_s.get(c, 0))
        return steps
